--
-- Дамп данных таблицы `news`
--

INSERT INTO `news` (`id`, `name`, `description`, `date`, `preview`, `status`) VALUES
(2, 'Современная мода в сфере детских праздников', 'Времена стремительно меняются... Когда-то писком моды был «Юппи – просто добавь воды», потом родители придумали надувать ночью шарики накануне дня рождения чада. Сегодня же стоит лишь открыть сайт, и можно потратить 3 часа, изучая разнообразие шоу-программ, сюжетов спектаклей и видов кэнди-баров.Времена стремительно меняются...\r\n\r\nМы стараемся придерживаться самых новых тенденций. Но не просто модных, а по-настоящему добрых, веселых, развивающих и полезных во всех смыслах. И составили фирменный список тенденций, которые считаем лучшими.\r\n\r\nВ тренде «объемные» по восприятию праздники. Плоские баннеры и стандартные шарики уходят в прошлое. Сейчас атмосферу праздника создают не только визуальные образы, а еще и потрясающий звук, свет, ароматы. Сказочная реальность для детей – как достойная альтернатива виртуальной реальности для взрослых.                                                                       ', '2023-11-14', 'img/uploads/news/news1.png', 0),
(3, 'Москвичи активно бронируют Дедов Морозов', 'Социологические исследования, традиционно проводимые туротраслью в преддверии новогодних каникул, констатирует: большинство россиян (67%) собираются отмечать Новый 2024 год дома. Каждый девятый отправится в гости к родственникам или друзьям, а 2% граждан и вовсе не намерены праздновать. Но какой Новый год без Деда Мороза и Снегурочки? Хотя бы для того, чтобы порадовать детей.\r\n\r\nМосквичи уже начали бронировать поздравление на дому от Деда Мороза и Снегурочки. На одном из сайтов бесплатных объявлений эту информацию aif.ru подтвердили: «Уже вовсю идет бронь! Заказывать надо чем раньше, тем лучше. Есть вероятность, что свободных мест будет мало».\r\n\r\nВ прошлом году в Москве услуги новогодних аниматоров в среднем стоили 2,5 тыс. руб. В этом сезоне их услуги подорожали, что подтверждают выставленные расценки — очный визит сказочных персонажей домой начинается от 3−4 тыс. руб. Выступление новогодней пары длится от 15 до 40 минут.', '2023-12-01', 'img/uploads/news/1548207546_145 0 2874 2047_1920x0_80_0_0_6ba30268edeea2817dd90a8d20638d70.jpg', 0),
(7, 'Детские праздники: Дед Мороз по скайпу и елки-шоу', 'Варю ждет в гости Дед Мороз, в первый раз в жизни. Пригласительный дали ее маме на работе, предупредив, что взрослым вход платный – по полторы тысячи рублей. Теперь перед мамой стоит выбор – потратиться на праздник, а они с мужем эти расходы не планировали, или не ходить вовсе, оставив дочь без сказки.\r\n\r\n«Не знаю всей семьей пойдем или один из родителей. Плюс еще подарки, все это будет покупаться. Ребенок хоть и маленький, но все понимает, требует. Встанет не в одну копеечку», - рассказывает мама Вари Мария Балясникова .\r\n\r\nРынок детских развлечений растет. Ноу-хау этого года стало поздравление Деда Мороза по скайпу. На сегодня это, пожалуй, самая дешевая услуга, стоит 900 рублей в час. Посещение елки дороже.\r\n\r\nНа самое грандиозное новогоднее шоу в Москве, посмотреть которое приезжают даже из Владивостока, билеты начали покупать еще в июле. Сегодня в зрительном зале мест нет. Раскуплены были балкон за 400 рублей, партер за 4500 тысячи и все шесть вип-диванов, которые стоят в первом ряду от сцены. Их стоимость 36 тысяч рублей.', '2023-11-28', 'img/uploads/news/1277790280460.8833.jpg', 0),
(8, 'Высокая стоимость детских праздников', 'В Сургуте родители возмущены стоимостью организации детских праздников в городских развлекательных центрах. По словам сургутян, трехчасовой праздник с программой обойдется минимум в 15 тысяч рублей, сообщила URA.RU мама троих детей Ольга Харитонова.\r\n\r\n«Праздник дня рождения ребенка в каком-нибудь парке аттракционов или батутном центре обходится минимум в 15 тысяч рублей. При этом без включения в стоимость еды. Детям тяжело объяснить, что такой праздник не всем родителям по карману», — рассказала журналисту агентства Харитонова.\r\n\r\nОднако некоторые родители из Сургута считают, что экономить на детских праздниках не стоит. «У ребенка из детства должно остаться воспоминание о его классном дне рождении. Пускай сумма за организацию доходит и до 50 тысяч рублей, за то ребенок будет знать, что он важный в семье человек», — отметила участница группового чата «РодКом 86 Сургут» в мессенджере Viber.', '2023-11-21', 'img/uploads/news/nxmev70PGgQ.jpg', 0),
(9, 'Как в парках Москвы отметят день матери', 'С 24 по 26 ноября столичные парки организуют творческие и познавательные занятия, а также игры и концерты для детей и взрослых. Все они пройдут бесплатно. Это отличная возможность провести время всей семьей и встретить один из самых трогательных праздников — День матери. Он отмечается в нашей стране в последнее воскресенье осени, в этом году — 26 ноября.\r\n\r\n«Ко Дню матери наши парки подготовили душевные семейные мероприятия. На 18 парковых территориях пройдут бесплатные концерты, творческие мастер-классы и даже квесты, посвященные здоровому образу жизни. Праздничные программы позволят жительницам Москвы интересно провести время вместе с детьми, а у юных посетителей будет возможность сделать оригинальные подарки для любимых мам», — рассказал Министр Правительства Москвы, руководитель Департамента культуры города Алексей Фурсин. Подготовить подарки к празднику: программа на 24 и 25 ноября.', '2023-11-24', 'img/uploads/news/mutter.jpg', 0),
(10, 'Как в Зеленоградске отметили день рождения Деда мороза', 'В субботу, 18 ноября, в России отмечали день рождения Деда Мороза. По уже сложившейся традиции волшебник посетил Зеленоградск.\r\n\r\nПришедших на праздник в 13:00 на главную городскую площадь ждали игры, соревнования, хороводы, песенные конкурсы и сладкие угощения. Как прошло мероприятие, показал фотокорреспондент «Клопс».', '2023-11-29', 'img/uploads/news/ded.jpg', 0);

