  `question` varchar(100) NOT NULL,
  `answer` varchar(1000) NOT NULL,
  `status` int(11) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

--
-- Дамп данных таблицы `questions`
--

INSERT INTO `questions` (`id`, `question`, `answer`, `status`) VALUES
(1, 'Почему у вас такие низкие цены?', 'Мы не берем большие комиссионные, работаем с собственным штатом артистов или с проверенными аниматорами, положительно себя зарекомендовавшими, с которыми работаем длительное время по, соответственно, более низкой цене. За счет отсутствия третьих лиц, цена складывается только из гонорара артистов без накрутки сверху.', 0),
(2, 'Как выбрать персонажа на детский праздник?', 'Вверху, есть кнопки с возрастом ребенка.Вы просто нажимаете на возраст именинника и видите все программы, которые могут ему подойти.Выбирать программу лучше всего вместе с ребенком, если не планируется сюрприз. Или самостоятельно маме/папе, так как родители лучше знают кого хочет видеть ребенок.', 0),
(3, 'Какие программы самые популярные для дня рождения ребенка?', 'Самое популярное наполнение Дня Рождения ребенка: конкурсная игровая программа, развлечения и мастер-классы. Дети на празднике веселятся и играют, любуются героями, а так же могут научиться чему-то новому.Но, кроме этого, существуют важные дополнительные услуги, которые не дают детям устать и вносят разнообразие.', 0),
(4, 'Какие программы лучше выбрать для детей 2-4 года?', 'Если Вы планируете мероприятие для малышей, советуем учесть, что малыши могут быстро устать и Поэтому, программа на день рождения ребенка, не должна быть продолжительной.Вам нужно веселье с добрыми детскими героями: Лунтиком, Зайчиком, Машей и медведем и т.д. Можно также позвать дрессированных животных. Малыши любят зверушек. Но конечно же маленькие дети любят больше всего мыльные пузыри. Это интерактивное развлечение, ребята сами могут пробовать надувать пузыри разных размеров и форм, а ловить их – не менее увлекательно.', 0),
(5, 'Когда приглашать аниматора? Будет ли ждать аниматор гостей на празднике?', 'Рекомендуем дать детям минут 30-40 на то, чтобы пообщаться между собой и немного перекусить, а дальше — самое время для встречи с героями 10 сказок. Если вы знаете, что гости могут задержаться, то лучше пригласить аниматора через час. Аниматор за 20-30 минут до назначенного времени. Если Ваши гости задерживаются, аниматор может подождать максимум 10 минут. Через 10 минут будет считаться время работы. По расписанию у аниматора обычно следует другой детское мероприятие. Другие дети не будут ждать.', 0);

